// client/src/hooks/useTelegram.js
import { useEffect, useState } from 'react';

export function useTelegram() {
  const [tg, setTg] = useState(null);
  const [user, setUser] = useState(null);

  useEffect(() => {
    // Проверяем наличие Telegram WebApp API
    if (window.Telegram?.WebApp) {
      const webApp = window.Telegram.WebApp;
      setTg(webApp);

      try {
        const userData = webApp.initDataUnsafe?.user;
        if (userData) {
          setUser(userData);
        }
      } catch (error) {
        console.error('Ошибка при получении данных пользователя Telegram:', error);
      }

      // Настраиваем внешний вид Telegram WebApp
      webApp.expand();
      webApp.enableClosingConfirmation();

      // Устанавливаем тему
      const colorScheme = webApp.colorScheme || 'light';
      document.documentElement.dataset.theme = colorScheme;

      // Кнопка назад
      webApp.BackButton.isVisible = false;
    } else {
      console.log('Telegram WebApp API не обнаружен. Используется режим разработки.');

      // Создаем заглушку для режима разработки
      setTg({
        ready: () => console.log('Telegram WebApp ready (mock)'),
        expand: () => console.log('Telegram WebApp expand (mock)'),
        enableClosingConfirmation: () => console.log('Closing confirmation enabled (mock)'),
        BackButton: {
          isVisible: false,
          onClick: () => {},
          show: () => {},
          hide: () => {}
        },
        close: () => console.log('Closing WebApp (mock)'),
        colorScheme: 'light',
        initDataUnsafe: {
          user: {
            id: 123456789,
            username: 'test_user',
            first_name: 'Test',
            last_name: 'User'
          }
        }
      });

      // Устанавливаем тестового пользователя
      setUser({
        id: 123456789,
        username: 'test_user',
        first_name: 'Test',
        last_name: 'User'
      });
    }
  }, []);

  // Функция для показа/скрытия кнопки назад
  const showBackButton = (show = true) => {
    if (tg && tg.BackButton) {
      tg.BackButton.isVisible = show;
    }
  };

  // Функция для установки действия при нажатии на кнопку назад
  const onBackButtonClick = (callback) => {
    if (tg && tg.BackButton) {
      tg.BackButton.onClick(callback);
    }
  };

  // Функция для закрытия Telegram WebApp
  const closeApp = () => {
    if (tg) {
      tg.close();
    }
  };

  return {
    tg,
    user,
    showBackButton,
    onBackButtonClick,
    closeApp
  };
}
